server/tests/test_transform.py :: test_filter_grayscale_outputs_equal_channels
def test_filter_grayscale_outputs_equal_channels() -> None:
    raster = solid_raster(4, 4, 100, 150, 200)
    gray = filter_grayscale(raster)
    for index in range(0, len(gray.data), 3):
        assert gray.data[index] == gray.data[index + 1] == gray.data[index + 2]

server/tests/test_transform.py :: test_apply_post_filter_unknown_raises
def test_apply_post_filter_unknown_raises() -> None:
    raster = solid_raster(4, 4, 10, 10, 10)
    try:
        apply_post_filter(raster, "invalid")
    except ValueError as error:
        assert "finish filter" in str(error).lower()
    else:
        raise AssertionError("Expected ValueError")
